"use strict";(self.webpackChunkshareme=self.webpackChunkshareme||[]).push([["4064"],{47580(n){n.exports=JSON.parse('{"tag":{"label":"wecon","permalink":"/shareme/inverter/tags/wecon","allTagsPath":"/shareme/inverter/tags","count":4,"items":[{"id":"wecon/registers-rs485-wecon","title":"B\u1EA3n \u0110\u1ED3 Thanh Ghi & H\u01B0\u1EDBng D\u1EABn Truy\u1EC1n Th\xf4ng RS-485 Modbus RTU Bi\u1EBFn T\u1EA7n WECON VM","description":"Bi\u1EBFn t\u1EA7n WECON VM Series t\xedch h\u1EE3p s\u1EB5n c\u1ED5ng truy\u1EC1n th\xf4ng n\u1ED1i ti\u1EBFp RS-485 (h\u1ED7 tr\u1EE3 giao th\u1EE9c Modbus RTU chu\u1EA9n c\xf4ng nghi\u1EC7p). T\xednh n\u0103ng n\xe0y cho ph\xe9p \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung bi\u1EBFn t\u1EA7n t\u1EEB h\u1EC7 th\u1ED1ng PLC (Siemens, Mitsubishi, Omron, WECON...) ho\u1EB7c m\xe0n h\xecnh HMI/m\xe1y t\xednh SCADA \u0111\u1EC3 \u0111\u1ECDc/ghi l\u1EC7nh v\u1EADn h\xe0nh, gi\xe1m s\xe1t th\xf4ng s\u1ED1 th\u1EDDi gian th\u1EF1c v\xe0 c\xe0i \u0111\u1EB7t tham s\u1ED1 t\u1EEB xa.","permalink":"/shareme/inverter/wecon/registers-rs485-wecon"},{"id":"wecon/error-codes-wecon","title":"B\u1EA3ng M\xe3 L\u1ED7i Bi\u1EBFn T\u1EA7n WECON VM V\xe0 H\u01B0\u1EDBng D\u1EABn X\u1EED L\xfd S\u1EF1 C\u1ED1 (User Manual V2.0)","description":"Khi x\u1EA3y ra s\u1EF1 c\u1ED1 trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh, bi\u1EBFn t\u1EA7n WECON VM Series s\u1EBD ng\u1EAFt ng\xf5 ra \u0111\u1EC3 b\u1EA3o v\u1EC7 thi\u1EBFt b\u1ECB v\xe0 hi\u1EC3n th\u1ECB m\xe3 l\u1ED7i d\u1EA1ng ERRXX tr\xean b\xe0n ph\xedm (\u0111\u1ED3ng th\u1EDDi \u0111\xe8n ALARM nh\u1EA5p nh\xe1y).","permalink":"/shareme/inverter/wecon/error-codes-wecon"},{"id":"wecon/parameter-configuration-wecon","title":"B\u1EA3ng M\xe3 Tham S\u1ED1 C\xe0i \u0110\u1EB7t Chi Ti\u1EBFt Bi\u1EBFn T\u1EA7n WECON VM (Function Codes F0 - FD)","description":"T\xe0i li\u1EC7u n\xe0y t\u1ED5ng h\u1EE3p to\xe0n b\u1ED9 b\u1EA3ng m\xe3 tham s\u1ED1 ch\u1EE9c n\u0103ng (Function Codes) c\u1EE7a d\xf2ng bi\u1EBFn t\u1EA7n WECON VM Series d\u1EF1a tr\xean s\u1ED5 tay h\u01B0\u1EDBng d\u1EABn ch\xednh th\u1EE9c phi\xean b\u1EA3n V2.0 (20251203).","permalink":"/shareme/inverter/wecon/parameter-configuration-wecon"},{"id":"wecon/wecon-manual","title":"S\u1ED5 Tay H\u01B0\u1EDBng D\u1EABn V\u1EADn H\xe0nh Bi\u1EBFn T\u1EA7n WECON VM Series (User Manual V2.0)","description":"Bi\u1EBFn t\u1EA7n WECON VM Series AC Drive (Phi\xean b\u1EA3n t\xe0i li\u1EC7u chu\u1EA9n V2.0) l\xe0 d\xf2ng bi\u1EBFn t\u1EA7n \u0111a n\u0103ng cao c\u1EA5p c\u1EE7a h\xe3ng WECON, h\u1ED7 tr\u1EE3 c\xf4ng su\u1EA5t t\u1EEB 0.4 kW \u0111\u1EBFn 1000.0 kW (Ngu\u1ED3n v\xe0o 1 pha 220V / 3 pha 380V). \u0110i\u1EC3m \u0111\u1EB7c bi\u1EC7t n\u1ED5i b\u1EADt c\u1EE7a d\xf2ng WECON VM l\xe0 kh\u1EA3 n\u0103ng v\u1EADn h\xe0nh linh ho\u1EA1t cho c\u1EA3 \u0110\u1ED9ng c\u01A1 3 pha v\xe0 \u0110\u1ED9ng c\u01A1 1 pha (Single-Phase AC Motor), t\xedch h\u1EE3p s\u1EB5n b\u1ED9 \u0111i\u1EC1u khi\u1EC3n Vector, phanh DC, truy\u1EC1n th\xf4ng Modbus RTU v\xe0 b\u1ED9 PLC n\u1ED9i h\xe0m 16 c\u1EA5p t\u1ED1c \u0111\u1ED9.","permalink":"/shareme/inverter/wecon/wecon-manual"}],"unlisted":false}}')}}]);